final:
module RefModule(
  output [(1 - 1):0] op,
  input clk,
  input ce,
  input clr
);reg [(1 - 1):0] unused_op_reg;

  always @(posedge clk) begin
    if (clr) begin
      unused_op_reg <= 1'b0;
    end else if (ce) begin
      unused_op_reg <= 1'b1;
    end
  end

  assign op = unused_op_reg;
endmodule
